  ('colonel-7fec267e-moex-00066', 'colonel-7fec267e', 'colonel-7fec267e-moex-113-3a7b2121', 'sub-colonel-7fec267e-01', NULL, 'single_choice', '奎恩（R.Quinn）和麥克葛雷斯（M.McGrath）把組織文化分成四類，下列 何者符合「層級」的組織文化的特徵？', '["是典型的績效取向文化，強調社會公平的價值", "重視組織權力的集中與內部的整合，人員行為深受法規的約制", "偏好以授權與參與的方式，維繫內部的穩定和諧", "以抽象的遠景和領袖魅力，維持人員的工作士氣 30460"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:58+00:00", "source_pdf_sha1": "89ab12bb3bf9", "answer_pdf_sha1": "751e39132aa3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "304", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
  ('colonel-7fec267e-moex-00067', 'colonel-7fec267e', 'colonel-7fec267e-moex-113-3a7b2121', 'sub-colonel-7fec267e-01', NULL, 'single_choice', '政府人事體制的改革，其中包含績效導向系統的發展，因而更強調員工的工 作成果。此種人事改革背後的理論基礎為：', '["月暈效應（Haloeffect）", "新公共管理", "破窗理論", "長尾效應（Longtaileffect）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:58+00:00", "source_pdf_sha1": "89ab12bb3bf9", "answer_pdf_sha1": "751e39132aa3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "304", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
