  ('colonel-7fec267e-moex-00069', 'colonel-7fec267e', 'colonel-7fec267e-moex-113-3a7b2121', 'sub-colonel-7fec267e-01', NULL, 'single_choice', '過去在學界提出許多關於公共預算規模擴張的解釋，其中一個實證觀察指 出，當國家或社會遇到重大事件時，民眾較易支持增加稅收與支出以作為因 應，當事件結束後，支出規模卻已無法回復原先水準。以上實證觀察屬於下 列何者？', '["華格納法則（Wagner’sLaw）", "位移效果（DisplaceEffect）", "斷續均衡（PunctuatedEquilibrium）", "政治景氣循環（PoliticalBusinessCycle）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:58+00:00", "source_pdf_sha1": "89ab12bb3bf9", "answer_pdf_sha1": "751e39132aa3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "304", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "colonel", "civil_category": "一般行政"}'::jsonb, NULL),
